// src/components/ResultView.js
import React from "react";
import Quiz from "./Quiz";

export default function ResultView({data}) {
  if (!data) return null;
  const { text, quiz } = data;

  return (
    <div style={{marginTop:20}}>
      <div style={{
        padding:16,
        borderRadius:10,
        border:"1px solid #e6eef8",
        marginBottom:18,
        background:"#fbfdff"
      }}>
        <h2 style={{color:"#0b61d6", marginTop:0}}>Extracted Text</h2>
        <pre style={{
          whiteSpace:"pre-wrap",
          background:"white",
          padding:12,
          borderRadius:8,
          border:"1px solid #e6eef8"
        }}>{text}</pre>
      </div>

      <div id="quiz-container">
        <Quiz items={quiz || []} extractedText={text} />
      </div>
    </div>
  );
}
